export type Cell = [number, number];

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countLiveNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (isAlive(x + dx, y + dy)) count++;
      }
    }
    return count;
  };

  const survivors = cells.filter(([x, y]) => {
    const n = countLiveNeighbors(x, y);
    return n === 2 || n === 3;
  });

  const candidateKeys = new Set<string>();
  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const cx = x + dx;
        const cy = y + dy;
        if (isAlive(cx, cy)) continue;
        const key = `${cx},${cy}`;
        if (candidateKeys.has(key)) continue;
        candidateKeys.add(key);
        candidates.push([cx, cy]);
      }
    }
  }
  const born = candidates.filter(([x, y]) => countLiveNeighbors(x, y) === 3);

  return [...survivors, ...born];
};

